DROP TABLE IF EXISTS `patientserviceentries`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `patientserviceentries` (
  `id` int NOT NULL AUTO_INCREMENT,
  `patientId` int NOT NULL,
  `serviceCode` varchar(64) NOT NULL,
  `serviceName` varchar(255) DEFAULT NULL,
  `source` enum('mssql','manual','import') NOT NULL DEFAULT 'mssql',
  `sourceRef` varchar(128) NOT NULL,
  `serviceDate` date DEFAULT NULL,
  `createdAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `patientServiceEntries_sourceRef_unique` (`sourceRef`),
  KEY `patientServiceEntries_patientId_idx` (`patientId`),
  KEY `patientServiceEntries_serviceCode_idx` (`serviceCode`),
  KEY `idx_patient_service_date` (`patientId`,`serviceCode`,`serviceDate`),
  KEY `idx_service_source_updated` (`source`,`updatedAt`)
) ENGINE=InnoDB AUTO_INCREMENT=24370 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

